import java.util.function.*;
public class MethodRef {
    static int doubleIt(int n) { return n * 2; }
    public static void main(String[] args) {
        IntUnaryOperator f = MethodRef::doubleIt;
        IntBinaryOperator add = Integer::sum;
        Supplier<String> hello = "hello"::toUpperCase;
        System.out.println(f.applyAsInt(7));
        System.out.println(add.applyAsInt(3, 4));
        System.out.println(hello.get());
    }
}
